mapper.select:
/* Baim04Mapper.selectDailyUserLinkPolicyList */ SELECT '' AS chk , A.CMPNY_CD AS cmpnyCd , A.SITE_CD AS siteCd , A.SITE_NO AS siteNo , A.SITE_NM AS siteNm , A.USE_YN AS useYn , A.DAY_LIMIT_CNT AS dayLimitCnt , CONCAT( A.CMPNY_CD , '-' , A.SITE_CD ) AS joinCd FROM ( SELECT A.CMPNY_CD , A.SITE_CD , A.SITE_NO , A.SITE_NM , IFNULL(B.USE_YN, 'N') AS USE_YN , B.DAY_LIMIT_CNT FROM TB_SITE A LEFT OUTER JOIN TB_DAILY_USER_LINK_POLICY B ON ( A.CMPNY_CD = B.CMPNY_CD AND A.SITE_CD = B.SITE_CD ) WHERE A.CMPNY_CD = #{token.gv_cmpnyCd}
AND A.SITE_CD = #{param.siteCd}
) A WHERE 1=1
AND A.USE_YN = #{param.useYn}

mapper.update:

	/* Baim04Mapper.saveDailyUserLinkPolicy */
    INSERT INTO TB_DAILY_USER_LINK_POLICY (
    	CMPNY_CD
    	, SITE_CD
    	, USE_YN
    	, DAY_LIMIT_CNT
    	, INSERT_NO
    	, INSERT_DATE
    	, UPDATE_NO
    	, UPDATE_DATE
   	)
   	VALUES(
   		#{token.gv_cmpnyCd}
   		, #{param.siteCd}
		, IFNULL(#{param.useYn}, 'Y')
		, #{param.dayLimitCnt}
		, #{token.gv_userId}
		, now()
		, #{token.gv_userId}
		, now() 
   	)
   	ON DUPLICATE KEY UPDATE
	    USE_YN		= IFNULL(#{param.useYn}, 'Y')
	    , DAY_LIMIT_CNT = #{param.dayLimitCnt}
	    , UPDATE_NO   	= #{token.gv_userId}
	    , UPDATE_DATE 	= NOW()

mapper.select:
    /* Baim04Mapper.selectDailyUserSlotCnt */
    SELECT COUNT(*) 
    FROM TB_DAILY_USER_SLOT
	WHERE CMPNY_CD = #{token.gv_cmpnyCd}
	  AND SITE_CD = #{param.siteCd}

mapper.update:
	/* Baim04Mapper.saveDailyUserSlot */
	INSERT INTO TB_DAILY_USER_SLOT (
    	CMPNY_CD
    	, SITE_CD
    	, SLOT_NO
    	, SLOT_TYPE
    	, FIXED_YN
    	, USE_YN
    	, CURR_USER_ID
    	, SLOT_STATUS
    	, INSERT_NO
    	, INSERT_DATE
    	, UPDATE_NO
    	, UPDATE_DATE
   	)
   	VALUES(
   		#{param.cmpnyCd}
   		, #{param.siteCd}
   		, #{param.slotNo}
   		, #{param.slotType}
   		, 'N'
		, 'Y'
		, ''
		, #{param.slotStatus}
		, #{token.gv_userId}
		, now()
		, #{token.gv_userId}
		, now() 
   	)
   	ON DUPLICATE KEY UPDATE
   		USE_YN		= IFNULL(#{param.useYn}, 'Y')
	    , UPDATE_NO   	= #{token.gv_userId}
	    , UPDATE_DATE 	= NOW()

mapper.delete:
/* Baim04Mapper.deleteDailyUserLinkPolicy */
DELETE FROM TB_DAILY_USER_LINK_POLICY
WHERE CMPNY_CD = #{token.gv_cmpnyCd}
  AND SITE_CD = #{param.siteCd}
